// TypeScript declaration for importing image and audio assets

declare module '*.jpg' {
  const value: any;
  export default value;
}

declare module '*.jpeg' {
  const value: any;
  export default value;
}

declare module '*.png' {
  const value: any;
  export default value;
}

declare module '*.webp' {
  const value: any;
  export default value;
}

declare module '*.mp3' {
  const value: number;
  export default value;
}

declare module '*.m4a' {
  const value: number;
  export default value;
}

declare module '*.aac' {
  const value: number;
  export default value;
}
